package com.kurlik.frontend.domain.useCases

import com.kurlik.frontend.domain.AppData
import com.kurlik.frontend.domain.entities.InitAppData

suspend fun initAppData(initAppData: InitAppData) {
    val authData = initAppData.kurlikApi.auth(initAppData.initData)
    AppData.Vars.Setters.token(authData.token)
    AppData.Vars.Setters.username(authData.username)
    AppData.Vars.Setters.userRooms(initAppData.kurlikApi.getUserRooms(AppData.Vars.token.value))
    AppData.Vars.Setters.allEvents(initAppData.kurlikApi.getAllEvents(AppData.Vars.token.value))
}