package com.kurlik.frontend.presentation.screens.mainScreen

import androidx.compose.foundation.Image
import androidx.compose.foundation.background
import androidx.compose.foundation.clickable
import androidx.compose.foundation.layout.Column
import androidx.compose.foundation.layout.Row
import androidx.compose.foundation.layout.fillMaxWidth
import androidx.compose.foundation.layout.padding
import androidx.compose.foundation.layout.size
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.material3.MaterialTheme
import androidx.compose.material3.Text
import androidx.compose.runtime.Composable
import androidx.compose.ui.Modifier
import androidx.compose.ui.draw.clip
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.unit.dp
import com.kurlik.frontend.domain.entities.RoomData
import kurlik.composeapp.generated.resources.Res
import kurlik.composeapp.generated.resources.group_placeholder
import org.jetbrains.compose.resources.painterResource

@Composable
fun RoomListItem(
    roomData: RoomData,
    onClick: () -> Unit
) {
    Column(
        modifier = Modifier
            .fillMaxWidth()
            .padding(2.dp)
            .clip(RoundedCornerShape(20.dp))
            .background(MaterialTheme.colorScheme.surface)
            .clickable(onClick = onClick)
            .padding(12.dp)
    ) {
        Row(
            modifier = Modifier.fillMaxWidth()
        ) {
            Column(modifier = Modifier.weight(1f)) {
                Text(
                    text = roomData.title,
                    color = MaterialTheme.colorScheme.onTertiary,
                    fontSize = MaterialTheme.typography.labelMedium.fontSize,
                    fontWeight = FontWeight.Black
                )
                Text(
                    lineHeight = MaterialTheme.typography.labelSmall.fontSize,
                    text = "Участников: ${roomData.participantsCount}",
                    color = MaterialTheme.colorScheme.onTertiary,
                    fontSize = MaterialTheme.typography.labelSmall.fontSize,
                    fontWeight = FontWeight.Thin
                )
            }
            Image(
                modifier = Modifier.size(70.dp),
                painter = painterResource(Res.drawable.group_placeholder),
                contentDescription = null
            )
        }
        Text(
            text = roomData.lastMessageText,
            color = MaterialTheme.colorScheme.onTertiary,
            fontSize = MaterialTheme.typography.labelSmall.fontSize,
            fontWeight = FontWeight.Thin
        )
    }
}