@Composable
fun EventsCarousel(
    onClick: (id: String) -> Unit
) {
    val eventsList by MainScreenState.Vars.eventsList.collectAsState()
    BoxWithConstraints {
        val width = maxWidth
        when(val data = eventsList) {
            EventsList.Loading -> {}
            EventsList.Error -> TODO()
            is EventsList.Success -> {
                Column {
                    val scrollState = rememberLazyListState()
                    LazyRow(state = scrollState) {
                        items(
                            items = data.events
                        ) { itemData ->
                            Box(
                                modifier = Modifier.padding(5.dp)
                            ) {
                                EventCardItem(
                                    width = width - 10.dp,
                                    eventCardData = itemData,
                                    onClick = {
                                        onClick(itemData.id)
                                    }
                                )
                            }
                        }
                    }
                    Spacer(modifier = Modifier.height(5.dp))
                    Indicator(
                        scrollState = scrollState,
                        itemsCount = data.events.size
                    )
                    LaunchedEffect(scrollState.isScrollInProgress) {
                        if (!scrollState.isScrollInProgress) {
                            val maxScrollOffset =
                                scrollState.layoutInfo.visibleItemsInfo.maxOfOrNull { it.offset } ?: 0
                            val currentIndex = scrollState.firstVisibleItemIndex
                            val currentOffset = scrollState.firstVisibleItemScrollOffset
                            if (currentOffset > 0) {
                                val targetIndex = if (currentOffset > maxScrollOffset) {
                                    currentIndex + 1
                                } else {
                                    currentIndex
                                }
                                scrollState.animateScrollToItem(targetIndex)
                            }
                        }
                    }
                }
            }
        }
    }
}


@Composable
private fun Indicator(
    scrollState: LazyListState,
    itemsCount: Int
) {
    Row(
        modifier = Modifier.fillMaxWidth(),
        horizontalArrangement = Arrangement.Center
    ) {
        repeat(itemsCount - 1) { id ->
            Box(
                modifier = Modifier
                    .size(4.dp)
                    .clip(CircleShape)
                    .background(
                        MaterialTheme.colorScheme.onTertiary.copy(
                            alpha = if (id == scrollState.firstVisibleItemIndex) 1f else 0.3f
                        )
                    )
            )
            Spacer(modifier = Modifier.width(4.dp))
        }
        Box(
            modifier = Modifier
                .size(4.dp)
                .clip(CircleShape)
                .background(
                    MaterialTheme.colorScheme.onTertiary.copy(
                        alpha = if (scrollState.firstVisibleItemIndex == itemsCount - 1) 1f else 0.3f
                    )
                )
        )
    }
}