package com.kurlik.frontend.presentation.screens.mainScreen

import androidx.compose.foundation.background
import androidx.compose.foundation.clickable
import androidx.compose.foundation.layout.Column
import androidx.compose.foundation.layout.Row
import androidx.compose.foundation.layout.Spacer
import androidx.compose.foundation.layout.height
import androidx.compose.foundation.layout.padding
import androidx.compose.foundation.layout.size
import androidx.compose.foundation.layout.width
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.material3.Icon
import androidx.compose.material3.MaterialTheme
import androidx.compose.material3.Text
import androidx.compose.runtime.Composable
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.draw.clip
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.unit.Dp
import androidx.compose.ui.unit.dp
import com.kurlik.frontend.presentation.entities.EventCardData
import kurlik.composeapp.generated.resources.Res
import kurlik.composeapp.generated.resources.calendar
import kurlik.composeapp.generated.resources.clock
import org.jetbrains.compose.resources.DrawableResource
import org.jetbrains.compose.resources.painterResource

@Composable
fun EventCardItem(
    width: Dp,
    eventCardData: EventCardData,
    onClick: () -> Unit
) {
    Column(
        modifier = Modifier
            .width(width)
            .clip(RoundedCornerShape(20.dp))
            .background(MaterialTheme.colorScheme.primary)
            .clickable(onClick = onClick)
            .padding(12.dp)
    ) {
        Row {
            TextWithIcon(
                text = eventCardData.time,
                icon = Res.drawable.clock
            )
            Spacer(modifier = Modifier.width(3.dp))
            TextWithIcon(
                text = eventCardData.date,
                icon = Res.drawable.calendar
            )
        }
        Spacer(modifier = Modifier.height(10.dp))
        Text(
            text = eventCardData.title,
            color = MaterialTheme.colorScheme.onPrimary,
            fontSize = MaterialTheme.typography.labelMedium.fontSize,
            fontWeight = FontWeight.Black
        )
        Text(
            lineHeight = MaterialTheme.typography.labelSmall.fontSize,
            text = eventCardData.place,
            color = MaterialTheme.colorScheme.onPrimary.copy(alpha = 0.8f),
            fontSize = MaterialTheme.typography.labelSmall.fontSize,
            fontWeight = FontWeight.Thin
        )
    }
}

@Composable
private fun TextWithIcon(text: String, icon: DrawableResource) {
    Row(
        modifier = Modifier
            .clip(RoundedCornerShape(24.dp))
            .background(MaterialTheme.colorScheme.onPrimary.copy(alpha = 0.2f))
            .padding(horizontal = 6.dp, vertical = 3.dp),
        verticalAlignment = Alignment.CenterVertically
    ) {
        Icon(
            modifier = Modifier.size(10.dp),
            painter = painterResource(icon),
            tint = MaterialTheme.colorScheme.onPrimary,
            contentDescription = null
        )
        Spacer(modifier = Modifier.width(3.dp))
        Text(
            text = text,
            fontSize = MaterialTheme.typography.labelSmall.fontSize,
            lineHeight = MaterialTheme.typography.labelSmall.fontSize,
            fontWeight = FontWeight.Thin,
            color = MaterialTheme.colorScheme.onPrimary
        )
    }
}