package com.kurlik.frontend.presentation.screenStates

import com.kurlik.frontend.domain.AppData
import com.kurlik.frontend.presentation.entities.EventsList
import com.kurlik.frontend.presentation.entities.RoomsList
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow

object MainScreenState {
    object Vars {
        val username = AppData.Vars.username
        private val _eventsList: MutableStateFlow<EventsList> = MutableStateFlow(EventsList.Loading)
        val eventsList: StateFlow<EventsList>
            get() = _eventsList.asStateFlow()
        private val _roomsList: MutableStateFlow<RoomsList> = MutableStateFlow(RoomsList.Loading)
        val roomsList: StateFlow<RoomsList>
            get() = _roomsList.asStateFlow()

        object Setters {
            fun eventsList(eventsList: EventsList) {
                _eventsList.value = eventsList
            }
            fun roomsList(roomsList: RoomsList) {
                _roomsList.value = roomsList
            }
        }
    }
}