package com.kurlik.frontend.domain

import com.kurlik.frontend.domain.entities.EventData
import com.kurlik.frontend.domain.entities.RoomData
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow

object AppData {

    object Vars {
        private val _token: MutableStateFlow<String> = MutableStateFlow("")
        val token: StateFlow<String>
            get() = _token.asStateFlow()
        private val _username: MutableStateFlow<String> = MutableStateFlow("")
        val username: StateFlow<String>
            get() = _username.asStateFlow()
        private val _userRooms: MutableStateFlow<List<RoomData>> = MutableStateFlow(emptyList())
        val userRooms: StateFlow<List<RoomData>>
            get() = _userRooms.asStateFlow()
        private val _allEvents: MutableStateFlow<List<EventData>> = MutableStateFlow(emptyList())
        val allEvents: StateFlow<List<EventData>>
            get() = _allEvents.asStateFlow()

        object Setters {
            fun token(token: String) {
                _token.value = token
            }

            fun userRooms(rooms: List<RoomData>) {
                _userRooms.value = rooms
            }

            fun allEvents(events: List<EventData>) {
                _allEvents.value = events
            }

            fun username(username: String) {
                _username.value = username
            }
        }
    }
}