package com.kurlik.frontend

import androidx.compose.runtime.*
import com.kurlik.frontend.data.FakeKurlikApiImpl
import com.kurlik.frontend.domain.AppData
import com.kurlik.frontend.domain.entities.InitAppData
import com.kurlik.frontend.domain.useCases.initAppData
import com.kurlik.frontend.presentation.entities.EventsList
import com.kurlik.frontend.presentation.entities.RoomsList
import com.kurlik.frontend.presentation.mappers.toEventCardData
import com.kurlik.frontend.presentation.screenStates.MainScreenState
import com.kurlik.frontend.presentation.screens.mainScreen.MainScreen
import com.kurlik.frontend.presentation.theme.KurlikTheme

@Composable
fun App(initData: String) {
    KurlikTheme {
        MainScreen()
    }
    LaunchedEffect(Unit) {
        initAppData(
            InitAppData(
                initData = initData,
                kurlikApi = FakeKurlikApiImpl()
            )
        )
            MainScreenState.Vars.Setters.eventsList(
                EventsList.Success(
                    events = AppData.Vars.allEvents.value
                        .map { it.toEventCardData() }
                )
            )
        MainScreenState.Vars.Setters.roomsList(
            RoomsList.Success(
                rooms = AppData.Vars.userRooms.value
            )
        )
    }
}