package com.kurlik.frontend.presentation.mappers

import com.kurlik.frontend.presentation.entities.EventCardData
import com.kurlik.frontend.domain.entities.EventData
import kotlinx.datetime.TimeZone
import kotlinx.datetime.toLocalDateTime
import kotlin.time.Instant
import kotlinx.datetime.Month

fun EventData.toEventCardData(): EventCardData {
    val localDateTime = Instant.fromEpochMilliseconds(date).toLocalDateTime(TimeZone.currentSystemDefault())
    val hour = localDateTime.hour.toString().padStart(2, '0')
    val minute = localDateTime.minute.toString().padStart(2, '0')
    val day = localDateTime.day
    val month = when (localDateTime.month) {
        Month.JANUARY   -> "янв"
        Month.FEBRUARY  -> "фев"
        Month.MARCH     -> "мар"
        Month.APRIL     -> "апр"
        Month.MAY       -> "мая"
        Month.JUNE      -> "июн"
        Month.JULY      -> "июл"
        Month.AUGUST    -> "авг"
        Month.SEPTEMBER -> "сен"
        Month.OCTOBER   -> "окт"
        Month.NOVEMBER  -> "ноя"
        Month.DECEMBER  -> "дек"
    }
    return EventCardData(
        id = id,
        title = title,
        place = place,
        time = "$hour:$minute",
        date = "$day $month"
    )
}